// Network protocol analyzer using libpcap for DPI and TCP stream reconstruction
#include <iostream>
#include <pcap.h>
#include <netinet/ip.h>
#include <netinet/tcp.h>
#include <netinet/ether.h>
#include <map>
#include <vector>
#include <string>

struct StreamKey {
    uint32_t src_ip, dst_ip;
    uint16_t src_port, dst_port;
    bool operator<(const StreamKey& o) const {
        return std::tie(src_ip, dst_ip, src_port, dst_port) < std::tie(o.src_ip, o.dst_ip, o.src_port, o.dst_port);
    }
};

class HeuristicEngine {
public:
    static void analyze(const u_char* payload, int len) {
        if (len > 0 && payload[0] == 0x47) {
            std::cout << "[!] Anomaly detected: Potential non-standard protocol traffic" << std::endl;
        }
    }
};

class StreamReconstructor {
    std::map<StreamKey, std::vector<u_char>> streams;
public:
    void process(const struct tcphdr* tcp, const u_char* payload, int len, uint32_t saddr, uint32_t daddr) {
        StreamKey key = {saddr, daddr, ntohs(tcp->source), ntohs(tcp->dest)};
        streams[key].insert(streams[key].end(), payload, payload + len);
        HeuristicEngine::analyze(payload, len);
    }
};

void packet_handler(u_char* user, const struct pcap_pkthdr* pkthdr, const u_char* packet) {
    struct ether_header* eth = (struct ether_header*)packet;
    if (ntohs(eth->ether_type) == ETHERTYPE_IP) {
        struct ip* ip = (struct ip*)(packet + sizeof(struct ether_header));
        if (ip->ip_p == IPPROTO_TCP) {
            struct tcphdr* tcp = (struct tcphdr*)(packet + sizeof(struct ether_header) + (ip->ip_hl << 2));
            int payload_len = pkthdr->len - (sizeof(struct ether_header) + (ip->ip_hl << 2) + (tcp->doff << 2));
            const u_char* payload = packet + (sizeof(struct ether_header) + (ip->ip_hl << 2) + (tcp->doff << 2));
            reinterpret_cast<StreamReconstructor*>(user)->process(tcp, payload, payload_len, ip->ip_src.s_addr, ip->ip_dst.s_addr);
        }
    }
}

int main(int argc, char* argv[]) {
    char errbuf[PCAP_ERRBUF_SIZE];
    pcap_t* handle = pcap_open_live("eth0", BUFSIZ, 1, 1000, errbuf);
    if (!handle) return 1;
    StreamReconstructor engine;
    pcap_loop(handle, 0, packet_handler, reinterpret_cast<u_char*>(&engine));
    pcap_close(handle);
    return 0;
}
