struct Entity { uint32_t id; };

class MemoryPool {
    void* pool;
    size_t size;
    size_t offset;
public:
    MemoryPool(size_t s) : size(s), offset(0) { pool = malloc(s); }
    ~MemoryPool() { free(pool); }
    void* allocate(size_t s) {
        if (offset + s > size) return nullptr;
        void* ptr = (char*)pool + offset;
        offset += s;
        return ptr;
    }
};

