// Minimalist cross-platform GUI framework header and implementation using Skia
#include "include/core/SkCanvas.h"
#include "include/core/SkSurface.h"
#include "include/core/SkPaint.h"
#include <vector>
#include <memory>
#include <functional>

struct Rect { float x, y, w, h; };

class Component {
public:
    Rect bounds;
    std::vector<std::unique_ptr<Component>> children;
    std::function<void(float, float)> onClick;

    virtual void render(SkCanvas* canvas) {
        for (auto& child : children) child->render(canvas);
    }

    bool hitTest(float x, float y) {
        return x >= bounds.x && x <= bounds.x + bounds.w && 
               y >= bounds.y && y <= bounds.y + bounds.h;
    }
};

class Button : public Component {
public:
    void render(SkCanvas* canvas) override {
        SkPaint paint;
        paint.setColor(SK_ColorBLUE);
        canvas->drawRect(SkRect::MakeXYWH(bounds.x, bounds.y, bounds.w, bounds.h), paint);
    }
};

class Window {
    std::vector<std::unique_ptr<Component>> root;
public:
    void add(std::unique_ptr<Component> c) { root.push_back(std::move(c)); }

    void handleInput(float x, float y) {
        for (auto& c : root) {
            if (c->hitTest(x, y) && c->onClick) c->onClick(x, y);
        }
    }

    void draw(SkCanvas* canvas) {
        for (auto& c : root) c->render(canvas);
    }
};
//END framework.hpp

// Implementation entry point for Skia backend integration
#include "framework.hpp"

void RenderFrame(SkSurface* surface, Window& win) {
    SkCanvas* canvas = surface->getCanvas();
    canvas->clear(SK_ColorWHITE);
    win.draw(canvas);
}
