// HFT Matching Engine with Lock-Free Order Book and DPDK-style interface
#include <iostream>
#include <atomic>
#include <vector>
#include <map>
#include <memory>

struct Order {
    uint64_t id;
    double price;
    uint32_t quantity;
    bool is_buy;
};

class LockFreeOrderBook {
    std::atomic<bool> lock{false};
    std::map<double, uint32_t, std::greater<double>> bids;
    std::map<double, uint32_t> asks;

public:
    void add_order(const Order& o) {
        while (lock.exchange(true, std::memory_order_acquire));
        if (o.is_buy) bids[o.price] += o.quantity;
        else asks[o.price] += o.quantity;
        lock.store(false, std::memory_order_release);
    }
};

int main() {
    LockFreeOrderBook engine;
    engine.add_order({1, 150.25, 100, true});
    return 0;
}
