// High-performance multithreaded web server using io_uring and C++20 coroutines
#include <iostream>
#include <vector>
#include <thread>
#include <liburing.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <fcntl.h>
#include <coroutine>
#include <sys/sendfile.h>

struct io_context {
    struct io_uring ring;
    io_context() { io_uring_queue_init(4096, &ring, 0); }
    ~io_uring_queue_exit(&ring);
};

struct task {
    struct promise_type {
        task get_return_object() { return {}; }
        std::suspend_never initial_suspend() { return {}; }
        std::suspend_never final_suspend() noexcept { return {}; }
        void return_void() {}
        void unhandled_exception() {}
    };
};

class server {
    int listen_fd;
    io_context ctx;
public:
    server(int port) {
        listen_fd = socket(AF_INET, SOCK_STREAM, 0);
        sockaddr_in addr{AF_INET, htons(port), INADDR_ANY};
        bind(listen_fd, (struct sockaddr*)&addr, sizeof(addr));
        listen(listen_fd, 128);
    }

    void run() {
        while (true) {
            struct io_uring_sqe* sqe = io_uring_get_sqe(&ctx.ring);
            io_uring_prep_accept(sqe, listen_fd, nullptr, nullptr, 0);
            io_uring_submit(&ctx.ring);

            struct io_uring_cqe* cqe;
            io_uring_wait_cqe(&ctx.ring, &cqe);
            int client_fd = cqe->res;
            io_uring_cqe_seen(&ctx.ring, cqe);

            std::thread([client_fd] {
                char buf[1024];
                read(client_fd, buf, 1024);
                int file_fd = open("index.html", O_RDONLY);
                sendfile(client_fd, file_fd, nullptr, 4096);
                close(file_fd);
                close(client_fd);
            }).detach();
        }
    }
};

int main() {
    server s(8080);
    s.run();
    return 0;
}
