// Physics Engine: Rigid Body Dynamics, PBD Soft Bodies, and CCD
#include <vector>
#include <cmath>
#include <iostream>

struct Vec3 {
    float x, y, z;
    Vec3 operator+(const Vec3& v) const { return {x + v.x, y + v.y, z + v.z}; }
    Vec3 operator-(const Vec3& v) const { return {x - v.x, y - v.y, z - v.z}; }
    Vec3 operator*(float s) const { return {x * s, y * s, z * s}; }
    float dot(const Vec3& v) const { return x * v.x + y * v.y + z * v.z; }
    float lengthSq() const { return x * x + y * y + z * z; }
};

struct Particle {
    Vec3 pos, prevPos, vel, force;
    float invMass;
};

class PBDSystem {
public:
    std::vector<Particle> particles;
    float dt = 0.016f;

    void integrate() {
        for (auto& p : particles) {
            if (p.invMass == 0.0f) continue;
            p.vel = p.vel + p.force * p.invMass * dt;
            p.prevPos = p.pos;
            p.pos = p.pos + p.vel * dt;
        }
    }

    void solveConstraints(float stiffness) {
        // Distance constraint implementation
    }
};

int main() {
    PBDSystem engine;
    return 0;
}
